# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3

app = Flask(__name__)
web3 = Web3(Web3.HTTPProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'))

def verify_signature(message, signature, address):
    message_hash = web3.solidityKeccak(['string'], [message])
    signer_address = web3.eth.account.recoverMessage(message_hash, signature=signature)
    return signer_address == Web3.toChecksumAddress(address)

@app.route('/verify_signature', methods=['POST'])
def verify():
    data = request.get_json()
    message = data['message']
    signature = data['signature']
    address = data['address']

    if verify_signature(message, signature, address):
        return jsonify({'status': 'success', 'message': 'Signature verified'})
    else:
        return jsonify({'status': 'error', 'message': 'Invalid signature'}), 403

if __name__ == '__main__':
    app.run(debug=True)